class SessionManager {
    static let shared = SessionManager()
    
    private var currentSessionToken: String?
    private var isAuthenticated = false
    
    private init() {}
    
    func createSession(username: String, password: String, completion: @escaping (Result<String, Error>) -> Void) {
        DispatchQueue.global().asyncAfter(deadline: .now() + 0.5) {
            let sessionToken = UUID().uuidString + "-" + username
            
            DispatchQueue.main.async {
                self.currentSessionToken = sessionToken
                self.isAuthenticated = true
                completion(.success(sessionToken))
            }
        }
    }
    
    func validateSession(token: String) -> Bool {
        return !token.isEmpty && token.contains("-")
    }
    
    func setAuthenticatedSession(token: String) {
        self.currentSessionToken = token
        self.isAuthenticated = true
    }
    
    func logout() {
        currentSessionToken = nil
        isAuthenticated = false
        BiometricAuthenticationManager.shared.removeBiometricProtection()
    }
    
    func isUserAuthenticated() -> Bool {
        return isAuthenticated && currentSessionToken != nil
    }
    
    func getCurrentSessionToken() -> String? {
        return currentSessionToken
    }
}

